// ============================================================
// Config — Variables de configuration Loc Immo
// ============================================================

return [{
  json: {
    DASHBOARD_URL: 'https://dashboard-loc-immo.vercel.app',
    SMTP_FROM_EMAIL: 'gustiez.dorian@neurolia.work',
    ADMIN_EMAIL: 'gustiez.dorian@neurolia.work',
  }
}];

// Lire les donnees d'erreur depuis le trigger (pas depuis $input qui vient de Config)
const errorData = $('Erreur detectee').first().json;
const execution = errorData.execution;
const workflow = errorData.workflow;

const errorMessage = execution?.error?.message || 'Erreur inconnue';
const errorNode = execution?.error?.node?.name || 'Inconnu';
const executionId = execution?.id || '-';
const executionUrl = execution?.url || '';
const workflowName = workflow?.name || 'Inconnu';
const workflowId = workflow?.id || '-';
const timestamp = new Date().toLocaleString('fr-FR', { timeZone: 'Europe/Paris' });

const html = `
<div style="font-family: -apple-system, sans-serif; max-width: 600px; margin: 0 auto;">
  <div style="background: #fef2f2; border: 2px solid #dc2626; border-radius: 8px; padding: 16px; margin-bottom: 16px;">
    <h2 style="color: #dc2626; margin: 0 0 8px 0;">Erreur workflow — ${workflowName}</h2>
    <p style="color: #991b1b; margin: 0; font-size: 14px;">${timestamp}</p>
  </div>

  <table border="0" cellpadding="10" style="width: 100%; border-collapse: collapse;">
    <tr style="border-bottom: 1px solid #e5e7eb;">
      <td style="color: #6b7280; width: 140px;"><strong>Workflow</strong></td>
      <td>${workflowName} <code>(${workflowId})</code></td>
    </tr>
    <tr style="border-bottom: 1px solid #e5e7eb;">
      <td style="color: #6b7280;"><strong>Node en erreur</strong></td>
      <td><code>${errorNode}</code></td>
    </tr>
    <tr style="border-bottom: 1px solid #e5e7eb;">
      <td style="color: #6b7280;"><strong>Message</strong></td>
      <td style="color: #dc2626;"><strong>${errorMessage}</strong></td>
    </tr>
    <tr style="border-bottom: 1px solid #e5e7eb;">
      <td style="color: #6b7280;"><strong>Execution</strong></td>
      <td><code>${executionId}</code></td>
    </tr>
  </table>

  ${executionUrl ? `<div style="margin-top: 16px; text-align: center;"><a href="${executionUrl}" style="display: inline-block; padding: 12px 24px; background: #dc2626; color: white; text-decoration: none; border-radius: 8px;">Voir l'execution n8n</a></div>` : ''}
</div>`;

return [{
  json: {
    subject: `[Loc Immo] ERREUR — ${workflowName} — ${errorNode}`,
    html,
  }
}];
